// src/spell/buildSpellContent.ts
init_templates();
init_migration();
init_YamlFrontmatter();
function buildSpellContent(spell) {
  const templateVersion = TEMPLATE_VERSIONS.spell || "1.1.0";
  const components = Array.isArray(spell.components) ? spell.components.join(", ") : "";
  const classes = Array.isArray(spell.classes) && spell.classes.length > 0 ? spell.classes.map((c) => c == null ? void 0 : c.name).filter(Boolean).join(", ") : "N/A";
  const description = Array.isArray(spell.desc) && spell.desc.length > 0 ? spell.desc.join("\n\n") : "Add spell description.";
  const higherLevel = Array.isArray(spell.higher_level) && spell.higher_level.length > 0 ? spell.higher_level.join("\n\n") : "N/A";
  let content = updateYamlFrontmatter(SPELL_TEMPLATE, (fm) => {
    var _a;
    return {
      ...fm,
      type: "spell",
      template_version: templateVersion,
      name: spell.name || "Spell",
      level: typeof spell.level === "number" ? spell.level : 1,
      school: ((_a = spell.school) == null ? void 0 : _a.name) || "",
      casting_time: spell.casting_time || "1 action",
      range: spell.range || "",
      components,
      duration: spell.duration || "",
      concentration: Boolean(spell.concentration),
      ritual: Boolean(spell.ritual),
      classes,
      source: spell.source || "SRD"
    };
  }).replace(/^# Spell$/m, `# ${spell.name || "Spell"}`);
  content = content.replace(
    /## Description\n[\s\S]*?\n## At Higher Levels/m,
    `## Description
${description}

## At Higher Levels`
  );
  content = content.replace(
    /## At Higher Levels\n[\s\S]*$/m,
    `## At Higher Levels
${higherLevel}

## Classes
${classes}`
  );
  return content;
}

