    this.addDetail(details, "\u{1F4CF} Range", spell.range);
    this.addDetail(details, "\u{1F3AD} Components", spell.components.join(", ") + (spell.material ? ` (${spell.material})` : ""));
    this.addDetail(details, "\u23F3 Duration", spell.duration);
    if (spell.concentration) {
      details.createEl("div", { text: "\u26A0\uFE0F Requires Concentration", cls: "spell-concentration" });
    }
